import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Dashboard() {
  const [activeTab, setActiveTab] = useState('analytics'); // analytics, restaurants, users
  const [analytics, setAnalytics] = useState({ salesPerRest: [], topItems: [], globalAvg: null });
  const [restaurants, setRestaurants] = useState([]);
  const [users, setUsers] = useState([]);

  // Forms
  const [newRest, setNewRest] = useState({ name: '', cuisine: '' });
  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'user', address: '', phone: '' });

  useEffect(() => {
    fetchAnalytics();
    fetchRestaurants();
    fetchUsers();
  }, []);

  const fetchAnalytics = async () => {
    try {
      const [salesRes, itemsRes, avgRes] = await Promise.all([
        axios.get('http://localhost:3000/analytics/sales-per-restaurant'),
        axios.get('http://localhost:3000/analytics/most-ordered-items'),
        axios.get('http://localhost:3000/analytics/average-order-value')
      ]);
      setAnalytics({ salesPerRest: salesRes.data, topItems: itemsRes.data, globalAvg: avgRes.data });
    } catch (err) { console.error(err); }
  };

  const fetchRestaurants = async () => {
    const res = await axios.get('http://localhost:3000/restaurants');
    setRestaurants(res.data);
  };

  const fetchUsers = async () => {
    const res = await axios.get('http://localhost:3000/users');
    setUsers(res.data);
  };

  const handleAddRestaurant = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:3000/restaurants', newRest);
    setNewRest({ name: '', cuisine: '' });
    fetchRestaurants();
  };

  const handleAddUser = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:3000/users/register', newUser);
    setNewUser({ name: '', email: '', password: '', role: 'user', address: '', phone: '' });
    fetchUsers();
  };

  return (
    <div>
      <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
        <button className={`button ${activeTab === 'analytics' ? '' : 'button-outline'}`} onClick={() => setActiveTab('analytics')}>PLATFORM ANALYTICS</button>
        <button className={`button ${activeTab === 'restaurants' ? '' : 'button-outline'}`} onClick={() => setActiveTab('restaurants')}>MANAGE CAFETERIAS</button>
        <button className={`button ${activeTab === 'users' ? '' : 'button-outline'}`} onClick={() => setActiveTab('users')}>USER CREDENTIALS</button>
      </div>

      {activeTab === 'analytics' && (
        <div>
          <div className="analytics-grid">
            <div className="analytic-card">
              <p>AVG ORDER VALUE</p>
              <div className="value">${analytics.globalAvg?.avgOrderValue.toFixed(2)}</div>
            </div>
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem', marginTop: '2rem' }}>
            <div>
              <h3>SALES BY CAFETERIA</h3>
              <table>
                <thead><tr><th>NAME</th><th>SALES</th></tr></thead>
                <tbody>{analytics.salesPerRest.map(r => <tr key={r._id}><td>{r.restaurantName}</td><td>${r.totalSales.toFixed(2)}</td></tr>)}</tbody>
              </table>
            </div>
            <div>
              <h3>TOP ITEMS (GLOBAL)</h3>
              <table>
                <thead><tr><th>ITEM</th><th>QTY</th></tr></thead>
                <tbody>{analytics.topItems.map(i => <tr key={i._id}><td>{i._id}</td><td>{i.totalQuantity}</td></tr>)}</tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'restaurants' && (
        <div style={{ background: 'white', padding: '2rem', borderRadius: '8px' }}>
          <h2>ADD NEW CAFETERIA</h2>
          <form onSubmit={handleAddRestaurant} style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
            <input type="text" placeholder="NAME" value={newRest.name} onChange={e => setNewRest({...newRest, name: e.target.value})} required className="input" style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <input type="text" placeholder="CUISINE" value={newRest.cuisine} onChange={e => setNewRest({...newRest, cuisine: e.target.value})} required className="input" style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <button type="submit" className="button">CREATE</button>
          </form>
          <hr />
          <h3>EXISTING CAFETERIAS</h3>
          <div className="restaurant-grid">
            {restaurants.map(r => (
              <div key={r._id} className="card" style={{ padding: '1rem' }}>
                <strong>{r.name}</strong> ({r.cuisine})
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div style={{ background: 'white', padding: '2rem', borderRadius: '8px' }}>
          <h2>REGISTER NEW USER / STAFF</h2>
          <form onSubmit={handleAddUser} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '2rem' }}>
            <input type="text" placeholder="NAME" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} required style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <input type="email" placeholder="EMAIL" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} required style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <input type="password" placeholder="PASSWORD" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} required style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <select value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value})} style={{ padding: '0.8rem', border: '1px solid #ddd' }}>
              <option value="user">USER (STUDENT)</option>
              <option value="admin">ADMIN</option>
              <option value="restaurant">RESTAURANT STAFF</option>
            </select>
            <input type="text" placeholder="ADDRESS" value={newUser.address} onChange={e => setNewUser({...newUser, address: e.target.value})} required style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <input type="text" placeholder="PHONE" value={newUser.phone} onChange={e => setNewUser({...newUser, phone: e.target.value})} required style={{ padding: '0.8rem', border: '1px solid #ddd' }} />
            <button type="submit" className="button" style={{ gridColumn: 'span 2' }}>REGISTER CREDENTIALS</button>
          </form>
          <hr />
          <h3>EXISTING CREDENTIALS</h3>
          <table>
            <thead><tr><th>NAME</th><th>EMAIL</th><th>ROLE</th></tr></thead>
            <tbody>{users.map(u => <tr key={u._id}><td>{u.name}</td><td>{u.email}</td><td><span className="status-badge">{u.role}</span></td></tr>)}</tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
